B.GI=new A.o("What is the normal MAP range over which cerebral autoregulation maintains constant blood flow?","50-150 mmHg.")
B.DZ=new A.o("According to the Monro-Kellie Doctrine, what are the three primary components of the rigid skull container?","Brain (~80%), blood (~10%), and CSF (~10%).")
B.Eg=new A.o("What is the BTF treatment threshold for intracranial pressure (ICP)?",">22 mmHg.")
B.GW=new A.o("What is the formula for calculating Cerebral Perfusion Pressure (CPP)?","CPP = MAP - ICP.")
B.F9=new A.o("What is the recommended target range for CPP in the management of severe TBI?","60-70 mmHg.")
