B.FU=new A.o("The Supervision Rating Scale (SRS) consists of 13 items describing what?","Supervision level and burden of care")
B.Fi=new A.o("At which Rancho Level does a patient first become 'Modified Independent,' handling multiple tasks and using compensatory strategies?","Level X")
